import { useState } from "react";
import { KanbanBoard } from "../../components/kanban/KanbanBoard";
import { boardConfig } from "./config";
import { initialCards } from "./data";
import { usePersonalTasksBoardCardChange, usePersonalTasksBoardLoadMore } from "./useCardChange";
import type { KanbanCardData } from "./types";

/**
 * My Tasks
 * Personal productivity board
 *
 * Drag-and-drop is powered by the project's custom Pointer DnD library
 * (no @dnd-kit dependency). Cards persist locally — wire `useCardChange`
 * to your backend to make moves stick across reloads.
 */
export default function PersonalTasksBoard() {
  const [cards, setCards] = useState<KanbanCardData[]>(initialCards);
  const handleCardChange = usePersonalTasksBoardCardChange();
  const handleLoadMore = usePersonalTasksBoardLoadMore();
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-xl font-bold">{boardConfig.title}</h2>
        {boardConfig.subtitle && (
          <p className="text-sm text-muted-foreground">{boardConfig.subtitle}</p>
        )}
      </div>
      <KanbanBoard
        config={boardConfig}
        cards={cards}
        onCardsChange={setCards}
        onCardChange={handleCardChange}
        onLoadMore={handleLoadMore}
      />
    </div>
  );
}

import type { KanbanBuilderConfig } from "./types";

/** Static configuration. All fields are typed and validated. */
export const boardConfig: KanbanBuilderConfig = {
  "title": "My Tasks",
  "subtitle": "Personal productivity board",
  "layout": "board",
  "columns": [
    {
      "id": "todo",
      "title": "To Do",
      "color": "amber"
    },
    {
      "id": "doing",
      "title": "Doing",
      "color": "blue"
    },
    {
      "id": "done",
      "title": "Done",
      "color": "emerald"
    }
  ],
  "visibleFields": [
    "priority",
    "dueDate"
  ],
  "enableDnd": true,
  "enableAddCard": true,
  "enableWipLimits": false,
  "showColumnTotals": true,
  "compactCards": false
};

import type { KanbanCardData } from "./types";

/** Initial card data. Swap with your own backend fetch when wiring up production. */
export const initialCards: KanbanCardData[] = [
  {
    "id": "p1",
    "columnId": "todo",
    "title": "Buy groceries",
    "priority": "low",
    "dueDate": "Apr 25"
  },
  {
    "id": "p2",
    "columnId": "todo",
    "title": "Renew gym membership",
    "priority": "medium"
  },
  {
    "id": "p3",
    "columnId": "doing",
    "title": "Read TanStack docs",
    "priority": "medium"
  },
  {
    "id": "p4",
    "columnId": "done",
    "title": "Pay electricity bill",
    "priority": "high"
  }
];

import { useCallback } from "react";
import type { KanbanCardData } from "./types";

/**
 * Called whenever a card is dropped into a new position via DnD.
 * Replace the body with your real backend call (e.g. fetch PATCH).
 */
export function usePersonalTasksBoardCardChange() {
  return useCallback((event: {
    card: KanbanCardData;
    fromColumnId: string;
    toColumnId: string;
    fromIndex: number;
    toIndex: number;
    cards: KanbanCardData[];
  }) => {
    console.log("[kanban] card moved:", event);
  }, []);
}

export function usePersonalTasksBoardLoadMore() {
  return useCallback(async (event: { columnId: string; cursor?: string }) => {
    console.log("[kanban] load more:", event);
  }, []);
}

/**
 * Re-export of the kanban engine types — imported by the generated component
 * so callers don't need to dig into the engine internals.
 */
export type {
  KanbanBuilderConfig,
  KanbanCardData,
  KanbanColumnConfig,
  KanbanCardField,
} from "../../components/kanban/types";
